// Compile yesterday's agent activity into an HTML email report
const activity = $input.first().json;
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];

const messages = activity?.messages || [];
const sessions = activity?.sessions || 0;
const topIntents = activity?.top_intents || [];
const avgResponseMs = activity?.avg_response_ms || 0;
const errors = activity?.errors || [];

// Build intent list HTML
const intentRows = topIntents.map((intent, i) => `
  <tr>
    <td>${i + 1}</td>
    <td>${intent.label || intent.name || 'Unknown'}</td>
    <td>${intent.count || 0}</td>
    <td>${intent.avg_sentiment || 'N/A'}</td>
  </tr>
`).join('');

// Build recent messages sample
const recentSample = messages.slice(0, 5).map(m => `
  <tr>
    <td>${m.channel || 'web'}</td>
    <td>${(m.text || m.message || '').substring(0, 80)}...</td>
    <td>${m.sentiment || 'neutral'}</td>
    <td>${m.timestamp || dateStr}</td>
  </tr>
`).join('');

// Error list
const errorRows = errors.length > 0 ? errors.map(e => `<li>${e.message || e}</li>`).join('') : '<li>No errors reported</li>';

const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>StudEx Daily Agent Report — ${dateStr}</title>
  <style>
    body { font-family: Arial, sans-serif; background: #f4f4f4; margin: 0; padding: 20px; }
    .container { max-width: 700px; margin: 0 auto; background: #fff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
    .header { background: #1a1a2e; color: #fff; padding: 24px; text-align: center; }
    .header h1 { margin: 0; font-size: 22px; }
    .header p { margin: 6px 0 0; opacity: 0.7; font-size: 14px; }
    .stats { display: flex; flex-wrap: wrap; padding: 20px; gap: 12px; }
    .stat { flex: 1; min-width: 120px; background: #f8f9fa; border-left: 4px solid #4f46e5; padding: 14px; border-radius: 4px; }
    .stat .label { font-size: 12px; color: #666; text-transform: uppercase; letter-spacing: 0.5px; }
    .stat .value { font-size: 28px; font-weight: bold; color: #1a1a2e; margin-top: 4px; }
    .section { padding: 20px 24px; border-top: 1px solid #eee; }
    .section h2 { margin: 0 0 12px; font-size: 16px; color: #1a1a2e; }
    table { width: 100%; border-collapse: collapse; font-size: 14px; }
    th { background: #f0f0f5; padding: 10px 8px; text-align: left; font-size: 12px; text-transform: uppercase; color: #666; }
    td { padding: 10px 8px; border-bottom: 1px solid #eee; }
    .badge { display: inline-block; padding: 2px 8px; border-radius: 12px; font-size: 11px; font-weight: bold; }
    .badge-positive { background: #d1fae5; color: #065f46; }
    .badge-negative { background: #fee2e2; color: #991b1b; }
    .badge-neutral { background: #f3f4f6; color: #374151; }
    .footer { background: #f8f9fa; padding: 16px 24px; text-align: center; font-size: 12px; color: #999; }
    .error-box { background: #fff1f2; border: 1px solid #fecdd3; border-radius: 6px; padding: 12px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>📊 StudEx Agent Daily Report</h1>
      <p>${dateStr} &nbsp;|&nbsp; Generated ${new Date().toISOString()} UTC</p>
    </div>

    <div class="stats">
      <div class="stat">
        <div class="label">Total Messages</div>
        <div class="value">${messages.length}</div>
      </div>
      <div class="stat">
        <div class="label">Active Sessions</div>
        <div class="value">${sessions}</div>
      </div>
      <div class="stat">
        <div class="label">Avg Response</div>
        <div class="value">${avgResponseMs}ms</div>
      </div>
      <div class="stat">
        <div class="label">Errors</div>
        <div class="value">${errors.length}</div>
      </div>
    </div>

    <div class="section">
      <h2>🏆 Top Intents</h2>
      ${topIntents.length > 0 ? `<table>
        <tr><th>#</th><th>Intent</th><th>Count</th><th>Sentiment</th></tr>
        ${intentRows}
      </table>` : '<p>No intent data available.</p>'}
    </div>

    <div class="section">
      <h2>💬 Recent Messages</h2>
      ${recentSample ? `<table>
        <tr><th>Channel</th><th>Message</th><th>Sentiment</th><th>Time</th></tr>
        ${recentSample}
      </table>` : '<p>No messages recorded.</p>'}
    </div>

    <div class="section">
      <h2>⚠️ Errors & Issues</h2>
      <div class="error-box">
        <ul style="margin:0; padding-left:18px;">${errorRows}</ul>
      </div>
    </div>

    <div class="footer">
      Generated by StudEx Super Agents &bull; Report for ${dateStr} &bull; studexagents.africa
    </div>
  </div>
</body>
</html>`;

return [{ json: { html, dateStr, messageCount: messages.length, sessions, errors: errors.length } }];

